package main

import "math"

// solve returns the minimum number of flips required to make s coherent.
func solve(s string) int64 {
	n := len(s)
	if n == 0 {
		return 0
	}

	// 1. Precompute prefix sums of '1's
	// P[i] stores the count of '1's in s[0...i-1]
	p := make([]int, n+1)
	for i := 0; i < n; i++ {
		p[i+1] = p[i]
		if s[i] == '1' {
			p[i+1]++
		}
	}

	totalOnes := p[n]
	totalZeros := n - totalOnes

	// Initialize minimum cost with costs for all 0s or all 1s
	// Case 1: Target 0^N (Cost = total ones)
	minCost := int64(totalOnes)

	// Case 2: Target 1^N (Cost = total zeros)
	if int64(totalZeros) < minCost {
		minCost = int64(totalZeros)
	}

	// Case 3: Target 0^A 1 0^B (Pivot k is the index of the single '1')
	// Iterate over all possible pivot positions k (0 to N-1)
	for k := 0; k < n; k++ {
		currentCost := 0

		// Cost to make s[k] = '1'
		if s[k] == '0' {
			currentCost++
		}

		// Cost to make s[0...k-1] = '0' (Count of '1's in prefix)
		// Count of '1's in s[0...k-1] is P[k]
		currentCost += p[k]

		// Cost to make s[k+1...N-1] = '0' (Count of '1's in suffix)
		// Count of '1's in s[k+1...N-1] is P[N] - P[k+1]
		currentCost += (totalOnes - p[k+1])

		if int64(currentCost) < minCost {
			minCost = int64(currentCost)
		}
	}

	return minCost
}
