package main

// solve calculates the minimum number of flips required to make the binary string s coherent.
func solve(s string) int64 {
	N := len(s)
	if N == 0 {
		return 0
	}

	// Precalculate prefix sums for '1's
	// P1[i] stores the count of '1's in s[0...i-1] (prefix of length i)
	P1 := make([]int, N+1)
	for i := 0; i < N; i++ {
		P1[i+1] = P1[i]
		if s[i] == '1' {
			P1[i+1]++
		}
	}

	// Cost to make all '0's (Target 0^N)
	C0 := int64(P1[N])

	// Cost to make all '1's (Target 1^N)
	// Total '0's = N - P1[N]
	C1 := int64(N) - int64(P1[N])

	minCost := C0
	if C1 < minCost {
		minCost = C1
	}

	// Cost to make the string of form 0* 1 0* (Target 0^p 1 0^{N-1-p})
	// Iterate over all possible positions p for the single '1' (0 <= p < N)
	for p := 0; p < N; p++ {
		// Cost 1: Flips needed in prefix s[0...p-1] to become all '0's.
		// This is the count of '1's in s[0...p-1] = P1[p].
		costPrefix := int64(P1[p])

		// Cost 2: Flip s[p] to '1'.
		costMid := int64(0)
		if s[p] == '0' {
			costMid = 1
		}

		// Cost 3: Flips needed in suffix s[p+1...N-1] to become all '0's.
		// This is the count of '1's in s[p+1...N-1].
		// Count of '1's in s[0...N-1] is P1[N].
		// Count of '1's in s[0...p] is P1[p+1].
		// Count of '1's in s[p+1...N-1] = P1[N] - P1[p+1].
		costSuffix := int64(P1[N] - P1[p+1])

		currentCost := costPrefix + costMid + costSuffix

		if currentCost < minCost {
			minCost = currentCost
		}
	}

	return minCost
}
